const getTicketStatistics = `-- name: GetTicketStatistics :one

SELECT
    COUNT(*) FILTER (WHERE status = 'open') as open_tickets,
    COUNT(*) FILTER (WHERE status = 'assigned') as assigned_tickets,
    COUNT(*) FILTER (WHERE status = 'in_progress') as in_progress_tickets,
    COUNT(*) FILTER (WHERE status = 'resolved') as resolved_tickets,
    COUNT(*) FILTER (WHERE status = 'closed') as closed_tickets,
    COALESCE(AVG(EXTRACT(EPOCH FROM (resolved_at - created_at))) FILTER (WHERE resolved_at IS NOT NULL), 0)::FLOAT as avg_resolution_time
FROM tickets
WHERE created_at >= $1
`

type GetTicketStatisticsRow struct {
	OpenTickets       int64   `json:"open_tickets"`
	AssignedTickets   int64   `json:"assigned_tickets"`
	InProgressTickets int64   `json:"in_progress_tickets"`
	ResolvedTickets   int64   `json:"resolved_tickets"`
	ClosedTickets     int64   `json:"closed_tickets"`
	AvgResolutionTime float64 `json:"avg_resolution_time"`
}

// ============================================================
// ANALYTICS & REPORTING
// ============================================================
func (q *Queries) GetTicketStatistics(ctx context.Context, createdAt time.Time) (GetTicketStatisticsRow, error) {
	row := q.db.QueryRowContext(ctx, getTicketStatistics, createdAt)
	var i GetTicketStatisticsRow
	err := row.Scan(
		&i.OpenTickets,
		&i.AssignedTickets,
		&i.InProgressTickets,
		&i.ResolvedTickets,
		&i.ClosedTickets,
		&i.AvgResolutionTime,
	)
	return i, err
}

