const upsertAgentMetrics = `-- name: UpsertAgentMetrics :one

INSERT INTO agent_metrics (support_admin_id, tickets_handled, tickets_resolved, average_resolution_time, average_response_time, customer_satisfaction_score, date)
VALUES ($1, $2, $3, $4, $5, $6, $7)
ON CONFLICT (support_admin_id, date)
DO UPDATE SET
    tickets_handled = agent_metrics.tickets_handled + EXCLUDED.tickets_handled,
    tickets_resolved = agent_metrics.tickets_resolved + EXCLUDED.tickets_resolved,
    average_resolution_time = EXCLUDED.average_resolution_time,
    average_response_time = EXCLUDED.average_response_time,
    customer_satisfaction_score = EXCLUDED.customer_satisfaction_score
RETURNING id, support_admin_id, tickets_handled, tickets_resolved, average_resolution_time, average_response_time, customer_satisfaction_score, date, created_at
`

type UpsertAgentMetricsParams struct {
	SupportAdminID            uuid.UUID      `json:"support_admin_id"`
	TicketsHandled            int32          `json:"tickets_handled"`
	TicketsResolved           int32          `json:"tickets_resolved"`
	AverageResolutionTime     sql.NullInt32  `json:"average_resolution_time"`
	AverageResponseTime       sql.NullInt32  `json:"average_response_time"`
	CustomerSatisfactionScore sql.NullString `json:"customer_satisfaction_score"`
	Date                      time.Time      `json:"date"`
}

// ============================================================
// AGENT METRICS
// ============================================================
func (q *Queries) UpsertAgentMetrics(ctx context.Context, arg UpsertAgentMetricsParams) (AgentMetric, error) {
	row := q.db.QueryRowContext(ctx, upsertAgentMetrics,
		arg.SupportAdminID,
		arg.TicketsHandled,
		arg.TicketsResolved,
		arg.AverageResolutionTime,
		arg.AverageResponseTime,
		arg.CustomerSatisfactionScore,
		arg.Date,
	)
	var i AgentMetric
	err := row.Scan(
		&i.ID,
		&i.SupportAdminID,
		&i.TicketsHandled,
		&i.TicketsResolved,
		&i.AverageResolutionTime,
		&i.AverageResponseTime,
		&i.CustomerSatisfactionScore,
		&i.Date,
		&i.CreatedAt,
	)
	return i, err
}
